+                        _ => {
+                            // Handle 256-color: 38;5;N or 48;5;N
+                            if let Some(rest) = seq.strip_prefix("38;5;") {
+                                if let Ok(n) = rest.parse::<u8>() {
+                                    current_fg = Some(ansi256_to_hex(n));
