+/// Convert ANSI 256-color index to hex color.
+fn ansi256_to_hex(n: u8) -> String {
+    match n {
+        // Standard colors (0-15)
+        0 => "#000000".to_string(),
+        1 => "#800000".to_string(),
+        2 => "#008000".to_string(),
+        3 => "#808000".to_string(),
+        4 => "#000080".to_string(),
+        5 => "#800080".to_string(),
+        6 => "#008080".to_string(),
+        7 => "#c0c0c0".to_string(),
+        8 => "#808080".to_string(),
+        9 => "#ff0000".to_string(),
+        10 => "#00ff00".to_string(),
+        11 => "#ffff00".to_string(),
+        12 => "#0000ff".to_string(),
+        13 => "#ff00ff".to_string(),
+        14 => "#00ffff".to_string(),
+        15 => "#ffffff".to_string(),
+        // 216 colors (16-231)
+        16..=231 => {
+            let n = n - 16;
+            let r = (n / 36) * 51;
+            let g = ((n % 36) / 6) * 51;
+            let b = (n % 6) * 51;
+            format!("#{r:02x}{g:02x}{b:02x}")
+        }
+        // Grayscale (232-255)
+        232..=255 => {
+            let gray = (n - 232) * 10 + 8;
+            format!("#{gray:02x}{gray:02x}{gray:02x}")
+        }
+    }
+}
+
+/// Strip ANSI escape codes from a string.
+fn strip_ansi(input: &str) -> String {
+    let mut result = String::with_capacity(input.len());
+    let mut in_escape = false;
+    for c in input.chars() {
+        if c == '\x1b' {
+            in_escape = true;
+            continue;
+        }
+        if in_escape {
+            if c == 'm' {
+                in_escape = false;
+            }
+            continue;
+        }
+        result.push(c);
+    }
+    result
+}
